import type React from 'react';
import type { PopperSidecarProps } from '../shared/components/popper-sidecar/shared';
import type { PopperRef } from '../shared/components/popper/PopperProvider';
import type { CompleteLocale, PartialLocale } from '../shared/locales/types';
import type { TooltipProps } from '../tooltip';
import type { DefaultSizeType } from '../util';
import type { TimezoneMetaTransformer } from '../pro/timezone-picker/types';
import type { PopupPortalContainerType } from '@universe-design/react-provider';
/**
 * @public
 * 阅读方向
 */
export type DirectionType = 'ltr' | 'rtl';
/**
 * @public
 * @docgen
 * 文字溢出弹层组件属性
 */
export type TextOverflowPopperSidecarProps = React.PropsWithChildren<Pick<TooltipProps, 'title' | 'disabled' | 'visible' | 'onVisibleChange' | 'checkOverflow'>>;
/**
 * @public
 */
export interface ConfigProviderProps extends React.PropsWithChildren<unknown> {
    /**
     * 设置统一样式前缀
     * @defaultValue `ud`
     */
    prefixCls?: string;
    /**
     * 本语言包配置
     */
    locale?: PartialLocale;
    /**
     * 组件尺寸
     * @defaultValue `medium`
     */
    componentSize?: DefaultSizeType;
    /**
     * 阅读方向
     */
    direction?: DirectionType;
    /**
     * 是否使用本地字体，默认 `false`，设置为 `true` 后会在 `body` 上添加一个 class。
     * 目前仅对 `zh` `ja` `en` 生效
     * @defaultValue false
     */
    useLocaleFontFamily?: boolean;
    /**
     * 弹出框（下拉选择，文字提示，菜单等等）渲染父节点，默认渲染到 `body` 上。
     * @defaultValue `body`
     */
    getPopupContainer?: PopupPortalContainerType;
    /**
     * affix 需要监听滚动事件的元素
     * @defaultValue `body`
     */
    getTargetContainer?: () => HTMLElement | typeof window;
    /**
     * toast 全局属性
     */
    toast?: {
        top?: number;
    };
    /**
     * 使用亮色模式还是暗色模式，该属性会影响一些使用了 css in js 的组件，比如 ColorPicker
     * @defaultValue `light`
     */
    theme?: 'dark' | 'light';
    /**
     * 自定义全局使用的 text-overflow 弹出提示的组件，默认是 `Tooltip` 的封装
     */
    textOverflowPopperSidecar?: React.ComponentType<TextOverflowPopperSidecarProps>;
    /**
     * (EXPERIMENTAL) 自定义弹层组件，组件库内置导出两种弹层组件，① 基于 `rc-trigger` 封装的 `RcTriggerPopperSidecar`，② 基于 `floating-ui` 封装的 `FloatingUIPopperSidecar`，目前版本默认使用 `RcTriggerPopperSidecar`。
     *
     * (DEPRECATED WARNING) 需要注意的是 `RcTriggerPopperSidecar` 不支持跟随滚动、安全边距等能力，未来的版本中将被废弃，建议局部使用 `FloatingUIPopperSidecar`。
     * @experimental
     * @see https://bytedance.feishu.cn/docx/doxcnOV9jgvO8NYmpyNxed4vzcb
     * @defaultValue `RcTriggerPopperSidecar`
     */
    PopperSidecar?: React.ComponentType<PopperSidecarProps & React.RefAttributes<PopperRef>>;
    timezone?: {
        /**
         * 用于在不同品牌下展示对应的时区名称
         * @experimental
         */
        metaTransformer?: TimezoneMetaTransformer;
    };
}
export interface ConfigProviderContextType extends Required<Pick<ConfigProviderProps, 'direction' | 'getPopupContainer' | 'getTargetContainer' | 'toast' | 'theme' | 'componentSize'>>, Pick<ConfigProviderProps, 'textOverflowPopperSidecar' | 'PopperSidecar'>, Pick<ConfigProviderProps, 'timezone'> {
    rootPrefixCls: string;
    locale: CompleteLocale;
}
